-- Celulares (SoloTodo category 6)
UPDATE products
SET category_id = (SELECT id FROM categories WHERE name = 'Celulares')
WHERE solotodo_id IN (76295,21007,22717,16106,15031,15030,15029,20309,21008,21016,21047,20298,15028,15027,16107,13467,13386,19439,16717,25993,20905,68192,87161,78926,100858,83355,91273,52533,67463,110121,109609,77377,77378,79801,79404,64201,94417,101087,100864,81954,68315,94891,60289,93852,95652,71192,67466,23078,25298,38810);

